**Scenario:** Multiple goroutines saving/loading simultaneously
```go
func TestMemoryStateStore_ConcurrentAccess(t *testing.T) {
    store := NewMemoryStateStore()
    var wg sync.WaitGroup

    for i := 0; i < 100; i++ {
        wg.Add(1)
        go func(id int) {
            defer wg.Done()
            task := &types.AgentTask{TaskID: fmt.Sprintf("task-%d", id)}
            state := types.TaskState{Task: task, UpdatedAt: time.Now()}
            store.Save(state.Task.TaskID, state)
        }(i)
    }
    wg.Wait()

    // Verify no data races or lost writes
    loaded, err := store.Load("task-50")
    if err != nil {
        t.Fatalf("Expected task-50 to exist after concurrent writes: %v", err)
    }
    if loaded.Task.TaskID != "task-50" {
        t.Errorf("Expected task-50, got %s", loaded.Task.TaskID)
    }
}
```

