func TestMemoryStateStore_SaveOverwrite(t *testing.T) {
    store := NewMemoryStateStore()
    task := &types.AgentTask{TaskID: "task-1", Status: types.TaskStatusPending}
    store.Save("task-1", types.TaskState{Task: task, UpdatedAt: time.Now()})

    task.Status = types.TaskStatusCompleted
    later := time.Now()
    store.Save("task-1", types.TaskState{Task: task, UpdatedAt: later})

    loaded, _ := store.Load("task-1")
    if loaded.Task.Status != types.TaskStatusCompleted {
        t.Errorf("Expected updated status, got %s", loaded.Task.Status)
    }
}
