```go
func TestOrchestrator_ExecuteTask_IdempotentSkip(t *testing.T) {
    orch := NewOrchestrator()
    ctx, cancel := context.WithCancel(context.Background())
    defer cancel()
    defer orch.Shutdown(context.Background())

    if err := orch.RegisterContract(testDefaultContract()); err != nil {
        t.Fatalf("Failed to register contract: %v", err)
    }
    if err := orch.Start(ctx); err != nil {
        t.Fatalf("Failed to start: %v", err)
    }

    task := &types.AgentTask{
        TaskID:     "idempotent-skip",
        ContractID: "default",
        Input:      map[string]any{"message": "test"},
        Status:     types.TaskStatusCompleted, // Already done
    }

    // Manually call executeTask - should be a no-op
    orch.executeTask(ctx, task)

    // Status should remain completed, not error
    status, _ := orch.GetTaskStatus("idempotent-skip")
    if status != types.TaskStatusCompleted {
        t.Errorf("Expected completed to stay completed, got %s", status)
    }
}
```

