**Scenario:** Calling Shutdown twice should be safe
```go
func TestOrchestrator_Shutdown_Idempotent(t *testing.T) {
    orch := NewOrchestrator()
    ctx := context.Background()

    orch.Start(ctx)
    err1 := orch.Shutdown(ctx)
    err2 := orch.Shutdown(ctx)

    if err1 != nil {
        t.Errorf("First shutdown should succeed, got: %v", err1)
    }
    if err2 != nil {
        t.Errorf("Second shutdown should succeed (idempotent), got: %v", err2)
    }
    if orch.IsRunning() {
        t.Error("Should not be running after shutdown")
    }
}
```

