func TestDispatcher_ExecuteHumanTask_UnexpectedCallStatus(t *testing.T) {
    contractExec := contractexec.NewContractExecutor()
    humanExec := &mockHumanExecutor{status: types.CallStatusUnknown}
    dispatch := NewDispatcher(contractExec, humanExec)
    dispatch.timeout = 100 * time.Millisecond

    task := &types.AgentTask{
        TaskID:     "unexpected-status",
        ContractID: "any",
        Input:      map[string]any{"prompt": "hello"},
        Metadata:   map[string]string{types.TaskMetadataKeyExecutor: types.ExecutorTypeHuman},
    }

    ctx := context.Background()
    result, err := dispatch.Dispatch(ctx, task)

    // Should handle unknown status gracefully (timeout or fail)
    if result == nil {
        t.Fatal("Result should not be nil")
    }
    if result.Status != types.TaskStatusFailed {
        t.Errorf("Expected failed for unexpected status, got %s", result.Status)
    }
}
